-- rebuild-net-links.sql
-- Wipes and rebuilds net_links from confirmed LLDP/CDP data (A48 + A24)
-- Run with: psql postgres://sccc:a-strong-password@localhost:5432/sccc_it -f rebuild-net-links.sql
-- Last updated: 2026-07-08

-- 1. Remove duplicate nodes created with wrong capitalization
DELETE FROM net_nodes WHERE hostname IN ('SW-A144-1-aruba','SW-A144-2-Aruba','SW-SoftBallPB');

-- 2. Remove corrupt node with # suffix
DELETE FROM net_nodes WHERE hostname = 'sw-aa144-a48#';

-- 3. Add missing nodes (NMBL storage, remote access switches)
ON CONFLICT (hostname) DO NOTHING;

-- 4. Wipe and rebuild all links
DELETE FROM net_links;

-- === A48 (sw-aa144-a48) links ===

-- === A24 (sw-aa144-a24) links ===

SELECT COUNT(*) AS total_links FROM net_links;
